def main():
    n = int(input())
    a = list(map(int, input().split()))
    d = [0] * n
    for i in range(n):
        if a[i] == 0:
            d[i] = 0
        else:
            j = i - 1
            while j >= 0 and a[j] != 0:
                j -= 1
            if j < 0:
                d[i] = i + 1
            else:
                d[i] = i - j
    print(' '.join(map(str, d)))

if __name__ == '__main__':
    main()
